+    BenchmarkSample {
+        domain,
+        benchmark_class: class,
+        baseline_value_millionths: baseline,
+        candidate_value_millionths: candidate,
+        sample_count: count,
+        epoch: epoch(),
+        content_hash: hash(b"workload"),
