+fn parity(
+    dim: ParityDimension,
+    domain: SpecializationDomain,
+    achieved: bool,
+    divergences: u64,
+    total: u64,
+) -> ParityFinding {
+    ParityFinding {
+        dimension: dim,
+        domain,
+        is_parity_achieved: achieved,
+        divergence_count: divergences,
+        total_comparisons: total,
+        detail: String::from("test finding"),
